func deviceDetailIcon(deviceType string) templ.Component {
	switch deviceType {
	case "desktop":
		return icons.Monitor(icons.WithSize(24))
	case "mobile":
		return icons.Smartphone(icons.WithSize(24))
	case "tablet":
		return icons.Tablet(icons.WithSize(24))
	default:
		return icons.Globe(icons.WithSize(24))
	}
}

func boolStr(b bool) string {
	if b {
		return "Yes"
	}
	return "No"
}

func sessionColSpan(u *user.User) string {
	if u != nil {
		return "md:col-span-2"
	}
	return "md:col-span-3"
}

